import { Edit as EditIcon } from "@mui/icons-material";
import { Divider, IconButton, TextField, useMediaQuery } from "@mui/material";
import Box from "@mui/material/Box";
import Container from "@mui/material/Container";
import Grid from "@mui/material/Grid";
import Typography from "@mui/material/Typography";
import { useTheme } from '@mui/material/styles';
import React, { useState } from "react";
import ButtonInput from "../components/ButtonInput/ButtonInput";
import CustomButton from "../components/CustomButton/CustomButton";
import Layout from "../components/Layout";
import { formatCep, formatCoupon, formatCpf, validateCpf, validateEmail } from "../utils/utils";

const debugColors = ['white', 'white', 'white', 'white', 'white', 'white', 'white', 'white']
// const debugColors = ['red', 'green', 'pink', 'blue', 'gray', 'lightBlue', 'orange', 'yellow']

enum Steps { Identification, Shipping, Payment }

type InputType = {
    value: string;
    error: boolean;
};

type Identification = {
    email: InputType;
    firstName: InputType;
    lastName: InputType;
    cpf: InputType;
    phone: InputType;
}

export default function Checkout() {
    const theme = useTheme();
    const isLargeScreen = useMediaQuery(theme.breakpoints.up('lg'));
    const [identification, setIdentification] = useState<Identification>({
        email: { value: '', error: false },
        firstName: { value: '', error: false },
        lastName: { value: '', error: false },
        cpf: { value: '', error: false },
        phone: { value: '', error: false },
    });

    const [cep, setCep] = useState<string>('');
    const [coupon, setCoupon] = useState<string>('');

    const [step, setStep] = useState<Steps>(Steps.Identification);

    const goToStep = (newStep: Steps) => {
        setStep(newStep);
    }

    const setError = (key: keyof Identification) => {
        setIdentification((prev) => ({
            ...prev,
            [key]: { ...prev[key], error: true }
        }))
    }

    const handleIdentification = () => {
        let hasError = false;
        if (!validateEmail(identification.email.value)) { 
            setError("email")
            hasError = true 
        }
        if (!validateCpf(identification.cpf.value)) { 
            setError("cpf")
            hasError = true 
        }


        if (!hasError) goToStep(Steps.Shipping);
    }

    const renderIdentificationForm = () => (
        <Grid container spacing={2} mt={1}>
            <Grid item xs={12} lg={12}>
                <TextField
                    label="E-Mail"
                    variant="outlined"
                    value={identification.email.value}
                    onChange={(event: React.ChangeEvent<HTMLInputElement>) =>
                        setIdentification((prev) => ({
                            ...prev,
                            email: { value: event.target.value, error: false },
                        }))
                    }
                    error={identification.email.error}
                    fullWidth
                />
            </Grid>
            <Grid item xs={12} lg={6}>
                <TextField
                    label="Primeiro Nome"
                    variant="outlined"
                    value={identification.firstName.value}
                    onChange={(event: React.ChangeEvent<HTMLInputElement>) =>
                        setIdentification((prev) => ({
                            ...prev,
                            firstName: { value: event.target.value, error: false },
                        }))
                    }
                    error={identification.firstName.error}
                    fullWidth
                />
            </Grid>
            <Grid item xs={12} lg={6}>
                <TextField
                    label="Último Nome"
                    variant="outlined"
                    value={identification.lastName.value}
                    onChange={(event: React.ChangeEvent<HTMLInputElement>) =>
                        setIdentification((prev) => ({
                            ...prev,
                            lastName: { value: event.target.value, error: false },
                        }))
                    }
                    error={identification.lastName.error}
                    fullWidth
                />
            </Grid>
            <Grid item xs={12} lg={6}>
                <TextField
                    label="CPF"
                    variant="outlined"
                    value={identification.cpf.value}
                    onChange={(event: React.ChangeEvent<HTMLInputElement>) =>
                        setIdentification((prev) => ({
                            ...prev,
                            cpf: { value: formatCpf(event.target.value), error: false },
                        }))
                    }
                    error={identification.cpf.error}
                    fullWidth
                />
            </Grid>
            <Grid item xs={12} lg={6}>
                <TextField
                    label="Telefone"
                    variant="outlined"
                    value={identification.phone.value}
                    onChange={(event: React.ChangeEvent<HTMLInputElement>) =>
                        setIdentification((prev) => ({
                            ...prev,
                            phone: { value: event.target.value, error: false },
                        }))
                    }
                    error={identification.phone.error}
                    fullWidth
                />
            </Grid>

            <Grid item xs={12} lg={12}>
                <CustomButton
                    title="Ir para a Entrega"
                    onClick={handleIdentification}
                    width='100%'
                />
            </Grid>
        </Grid>
    )

    const renderIdentificationContent = () => (
        <Box mt={1}>
            <Typography variant="body2" color="text.secondary">
                Email: teste@gmail.com
            </Typography>
            <Typography variant="body2" color="text.secondary">
                Nome: Guilherme Teste
            </Typography>
            <Typography variant="body2" color="text.secondary">
                Telefone: (31) 99999-9999
            </Typography>
        </Box>
    )

    const renderShippingForm = () => (
        <Grid container spacing={2} mt={1}>
            <Grid item xs={12} lg={12}>
                <ButtonInput
                    value={cep}
                    onChange={setCep}
                    onClick={() => console.log('todo')}
                    mask={formatCep}
                    label='INFORME O CEP'
                    buttonLabel='APLICAR'
                    width={isLargeScreen ? '100%' : '100%'}
                />
            </Grid>
            <Grid item xs={12} lg={12}>
                <TextField label="Endereço" variant="outlined" fullWidth />
            </Grid>
            <Grid item xs={12} lg={6}>
                <TextField label="Número" variant="outlined" fullWidth />
            </Grid>
            <Grid item xs={12} lg={6}>
                <TextField label="Complemento" variant="outlined" fullWidth />
            </Grid>
            <Grid item xs={12} lg={6}>
                <TextField label="Bairro" variant="outlined" disabled fullWidth />
            </Grid>
            <Grid item xs={12} lg={6}>
                <TextField label="Cidade" variant="outlined" disabled fullWidth />
            </Grid>
            <Grid item xs={4} lg={3}>
                <TextField label="UF" variant="outlined" disabled fullWidth />
            </Grid>
            <Grid item xs={8} lg={9}>
                <TextField label="Referência (opcional)" variant="outlined" fullWidth />
            </Grid>
            <Grid item xs={12} lg={12} mt={2}>
                <CustomButton
                    title="Ir para o Pagamento"
                    onClick={() => goToStep(Steps.Payment)}
                    width='100%'
                />
            </Grid>
        </Grid>
    )

    const renderShippingContent = () => {
        if (step === Steps.Identification)
            return <Box mt={1}>
                <Typography variant="body2" color="text.secondary">
                    Aguardando o preenchimento dos dados
                </Typography>

            </Box>
        else
            return <Box mt={1}>
                <Typography variant="body2" color="text.secondary">
                    CEP: 30190-050
                </Typography>
                <Typography variant="body2" color="text.secondary">
                    Endereço: Rua Cel. Antônio
                </Typography>
            </Box>
    }

    const renderPaymentForm = () => (
        <Grid container spacing={2} mt={1}>
            <Grid item xs={12} lg={12}>
                <TextField label="Forma de pagamento" variant="outlined" fullWidth />
            </Grid>
            <Grid item xs={12} lg={6}>
                <TextField label="Cartão" variant="outlined" fullWidth />
            </Grid>
        </Grid>
    )

    const renderPaymentContent = () => {
        if (step === Steps.Identification)
            return <Box mt={1}>
                <Typography variant="body2" color="text.secondary">
                    Aguardando o preenchimento dos dados
                </Typography>

            </Box>
        else
            return <Box mt={1}>
                <Typography variant="body2" color="text.secondary">
                    Forma de pagamento: cartão
                </Typography>
            </Box>
    }

    return (
        <Layout>
            <Container maxWidth="xl">
                <Grid container mt={4}>
                    <Grid item xs={12} lg={4} bgcolor={debugColors[0]} sx={{ border: 1, borderColor: '#ededed' }} pt={2} pl={4} pr={4} pb={4}>
                        <Box sx={{ display: 'flex', flexDirection: 'row', justifyContent: 'space-between', alignItems: 'center' }}>
                            <Typography variant="h6">
                                IDENTIFICAÇÃO
                            </Typography>
                            {step !== Steps.Identification &&
                                <IconButton
                                    onClick={() => goToStep(Steps.Identification)}
                                    edge="start"
                                >
                                    <EditIcon />
                                </IconButton>
                            }
                        </Box>
                        <Divider />
                        {step === Steps.Identification ? renderIdentificationForm() : renderIdentificationContent()}
                    </Grid>
                    <Grid item xs={12} lg={4} bgcolor={debugColors[0]} sx={{ border: 1, borderColor: '#ededed' }} pt={2} pl={4} pr={4} pb={4}>
                        <Box sx={{ display: 'flex', flexDirection: 'row', justifyContent: 'space-between', alignItems: 'center' }}>
                            <Typography variant="h6">
                                ENTREGA
                            </Typography>
                            {step === Steps.Payment &&
                                <IconButton
                                    onClick={() => goToStep(Steps.Shipping)}
                                    edge="start"
                                >
                                    <EditIcon />
                                </IconButton>
                            }
                        </Box>
                        <Divider />
                        {step === Steps.Shipping ? renderShippingForm() : renderShippingContent()}

                        <Box mt={4}>
                            <Typography variant="h6">
                                PAGAMENTO
                            </Typography>
                            <Divider />
                        </Box>
                        {step === Steps.Payment ? renderPaymentForm() : renderPaymentContent()}
                    </Grid>

                    <Grid item xs={12} lg={4} bgcolor='#f8f4f4' sx={{ border: 1, borderColor: '#ededed' }} p={4}>
                        <Typography variant="h6">
                            RESUMO DA COMPRA
                        </Typography>
                        <Divider />
                        <Box mt={2}>
                            <ButtonInput
                                value={coupon}
                                onChange={setCoupon}
                                mask={formatCoupon}
                                onClick={() => console.log('TODO')}
                                label='INSIRA O CUPOM'
                                buttonLabel='APLICAR'
                                width={isLargeScreen ? '70%' : '100%'}
                            />
                        </Box>
                        <Box mt={2}>
                            <Typography variant="body2" color="text.secondary">
                                Subtotal: R$ 199,90
                            </Typography>
                            <Typography variant="body2" color="text.secondary">
                                Frete: Grátis
                            </Typography>
                            <Typography variant="body2" color="text.secondary">
                                Cupom: 20
                            </Typography>
                            <Typography variant="body2" color="text.secondary">
                                Total: R$ 179,90
                            </Typography>
                        </Box>
                        {step === Steps.Payment &&
                            <Box mt={2}>
                                <CustomButton
                                    title="FINALIZAR COMPRA"
                                    onClick={() => console.log('todo')}
                                    width='100%'
                                />
                            </Box>
                        }
                    </Grid>
                </Grid>
            </Container>
        </Layout>
    );
}
