export const formatCoupon = (coupon: string) => {
    return coupon.toUpperCase();
}

export const validateCpf = (originalCpf: string): boolean => {
    let cpf = originalCpf.replace(/[^\d]+/g, '');
    if (cpf == '') return false;
    if (cpf.length != 11 ||
        cpf == "00000000000" ||
        cpf == "11111111111" ||
        cpf == "22222222222" ||
        cpf == "33333333333" ||
        cpf == "44444444444" ||
        cpf == "55555555555" ||
        cpf == "66666666666" ||
        cpf == "77777777777" ||
        cpf == "88888888888" ||
        cpf == "99999999999")
        return false;
    let add = 0;
    let i;
    for (i = 0; i < 9; i++)
        add += parseInt(cpf.charAt(i)) * (10 - i);
    let rev = 11 - (add % 11);
    if (rev == 10 || rev == 11)
        rev = 0;
    if (rev != parseInt(cpf.charAt(9)))
        return false;
    add = 0;
    for (i = 0; i < 10; i++)
        add += parseInt(cpf.charAt(i)) * (11 - i);
    rev = 11 - (add % 11);
    if (rev == 10 || rev == 11)
        rev = 0;
    if (rev != parseInt(cpf.charAt(10)))
        return false;
    return true;
}

export const formatCpf = (cpf: string): string => {
    // todo: melhorar essa funcao
    let formatted = cpf.replace(/\D/g, '');
    if (formatted.length === 11)
        return formatted.replace(/(\d{3})(\d{3})(\d{3})(\d{2})/, '$1.$2.$3-$4');
    else if (formatted.length === 10)
        return formatted.replace(/(\d{3})(\d{3})(\d{3})(\d{1})/, '$1.$2.$3-$4');
    else if (formatted.length === 9)
        return formatted.replace(/(\d{3})(\d{3})(\d{3})/, '$1.$2.$3');
    else if (formatted.length === 8)
        return formatted.replace(/(\d{3})(\d{3})(\d{2})/, '$1.$2.$3');
    else if (formatted.length === 7)
        return formatted.replace(/(\d{3})(\d{3})(\d{1})/, '$1.$2.$3');
    else if (formatted.length === 6)
        return formatted.replace(/(\d{3})(\d{3})/, '$1.$2');
    else if (formatted.length === 5)
        return formatted.replace(/(\d{3})(\d{2})/, '$1.$2');
    else if (formatted.length === 4)
        return formatted.replace(/(\d{3})(\d{1})/, '$1.$2');
    else if (formatted.length === 3)
        return formatted.replace(/(\d{3})/, '$1');
    else if (formatted.length === 2)
        return formatted.replace(/(\d{2})/, '$1');
    else if (formatted.length === 1)
        return formatted.replace(/(\d{1})/, '$1');
    else
        return formatted.substring(0, 11).replace(/(\d{3})(\d{3})(\d{3})(\d{2})/, '$1.$2.$3-$4');
}

